from collections import defaultdict
def build(edges):
    adj = defaultdict(set)
    for u, v in edges:
        adj[u].add(v); adj[v].add(u)
    return adj

def ego(adj, seed, k=1):
    layer = {seed}
    seen = {seed}
    for _ in range(k):
        nxt = set()
        for n in layer:
            for m in adj[n]:
                if m not in seen:
                    nxt.add(m); seen.add(m)
        layer = nxt
    return seen

