from collections import defaultdict, deque

def add_undirected(adj, u, v):
    adj[u].add(v); adj[v].add(u)

def bfs_path(adj, src, dst, max_depth=4):
    q = deque([(src, [src])])
    seen = {src}
    while q:
        n, path = q.popleft()
        if n == dst:
            return path
        if len(path) > max_depth:
            continue
        for m in sorted(adj.get(n, [])):
            if m not in seen:
                seen.add(m)
                q.append((m, path + [m]))
    return None

